def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.1:
            base = 1 - ratio
            for j in range(1, 10):
                mod = ((base ** j) * (j ** 2.5)) / (j*0.7 + 1)
                if j % 3 == 0:
                    mod *= 0.9
                else:
                    mod *= 1.1
                score += mod
            if capacity % 3 == 0:
                score *= 0.92
            if score > 7:
                score /= 4
        elif 0.1 <= ratio < 0.35:
            fact = 1
            for n in range(1, int(capacity // 3) + 2):
                fact *= n
                if fact > 1e6:
                    fact %= 10000
                    break
            mod_val = fact % 700
            score += np.sqrt(ratio * mod_val + 1)
            if capacity % 5 == 1 and (item * 4) % 1 == 0:
                score += 2.5
            else:
                score -= 0.3
            extra = 0
            for x in range(1, 7):
                pow_x = x ** 1.7
                frac = ((ratio * x) % 1)
                extra += frac * pow_x
            score += extra / 6
        elif 0.35 <= ratio <= 0.7:
            for m in range(1, 6):
                increment = (ratio ** (m + 2)) * (m ** 4) / (m + 2)
                if m % 2 == 1:
                    increment *= 1.05
                else:
                    increment *= 0.95
                score += increment
            remainder = capacity - item
            if remainder < 3:
                score += 8 + (remainder ** 0.9)
            else:
                score -= remainder * 0.6
            if score < 0:
                score = abs(score) * 0.3 + 1.5
            if int(capacity * 1.2) % 7 == 0:
                score *= 1.15
        elif 0.7 < ratio <= 1.0:
            penalty = 0
            for p in range(1, 10):
                penalty += ((ratio - 0.7) ** p) * np.sin(p * 0.5) * (p ** 1.5)
            score = penalty * 12
            if capacity < item * 1.05:
                score += 8
            if (int(capacity * 5) % 3 == 0) and (int(item * 15) % 7 == 0):
                score -= 6
            if score < 0:
                score = score * -1.3 + 3
            extend = 0
            for s in range(1,5):
                extend += ((ratio * s) % 1.3) * (s ** 2) * (0.7 if s%2==0 else 1.2)
            score += extend / 5
        elif 1.0 < ratio <= 1.4:
            base_penalty = 0
            diff = ratio - 1.0
            for q in range(1, 11):
                base_penalty += ((diff) ** q) * (q ** 2.2) * np.cos(q)
            score = base_penalty * 18
            if capacity < item * 1.3:
                score += 15
            if (int(capacity * 6) % 5 == 0) and (int(item * 13) % 4 == 0):
                score -= 7
            for z in range(2, 6):
                score += ((diff / z) % 1) * (z * 1.7)
            if score < 0:
                score = abs(score) * 0.5 + 2
        else:
            penalty = 0
            diff = ratio - 1.4
            for r in range(1, 12):
                power_val = ((diff) ** r)
                sign = -1 if r % 2 == 0 else 1
                penalty += power_val * (r ** 3) * sign
            score = penalty * 22
            if capacity < item * 2:
                score += 20
            if (int(capacity * 9) % 4 == 0) and (int(item * 8) % 3 == 0):
                score -= 8
            for w in range(3, 7):
                score += ((diff / w) % 1.5) * (w * 2)
            if score < 0:
                score = abs(score) * 0.55
            mult = 1 + (np.sin(capacity * 0.05) + np.cos(item * 0.1)) * 0.3
            score *= mult
        if capacity > 200:
            score /= (np.log1p(capacity) + 2)
        elif capacity < 5:
            score *= 2.1
        elif 50 < capacity < 80:
            score *= 1.22
        if abs(score) > 1500:
            score = np.sign(score) * 1500
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_val = 0
    else:
        top_thres = np.percentile(finite_priorities, 80)
        top_count = np.sum(finite_priorities > top_thres)
        fill_val = np.max(finite_priorities) * (15 + top_count)
    priorities[np.isinf(priorities)] = fill_val
    median_val = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    priorities[np.isnan(priorities)] = median_val
    for i in range(len(priorities)):
        if priorities[i] < 0:
            priorities[i] = abs(priorities[i]) ** 0.8
    return priorities
